import org.springframework.stereotype.Service;
import java.util.UUID;

@Service
public class TradeOrderService {
    private final MarketServiceClient marketClient;

    TradeOrderService(MarketServiceClient marketClient) {
        this.marketClient = marketClient;  // Feign proxy injected
    }

    public TradeConfirmation executeTrade(String userId, String symbol, int qty) {
        // Looks like local method calls — Feign makes HTTP calls:
        StockQuote quote = marketClient.getQuote(symbol);

        if (!quote.tradeable()) {
            throw new IllegalStateException(symbol + " is not currently tradeable");
        }

        marketClient.reserveShares(symbol, qty);

        String tradeId = "TRD-" + UUID.randomUUID().toString().substring(0, 8);
        return new TradeConfirmation(tradeId, symbol, qty, quote.price() * qty);
    }
}

