import feign.*;
import feign.codec.ErrorDecoder;
import org.springframework.context.annotation.*;

public class PaymentServiceErrorDecoder implements ErrorDecoder {
    @Override
    public Exception decode(String methodKey, Response response) {
        int status = response.status();
        return switch (status) {
            case 404 -> new PaymentNotFoundException("Payment not found");
            case 402 -> new InsufficientFundsException("Insufficient funds for payment");
            case 409 -> new DuplicatePaymentException("Duplicate payment detected");
            case 503 -> new PaymentServiceUnavailableException("Payment service unavailable");
            default  -> new RuntimeException("Payment service error: HTTP " + status);
        };
    }
}

@Configuration
class PaymentFeignConfig {
    @Bean
    public ErrorDecoder errorDecoder() {
        return new PaymentServiceErrorDecoder();
    }
}

