import org.springframework.stereotype.Service;

@FeignClient(name="user-svc",      url="${user.url}")      interface UserSvcClient      { @GetMapping("/api/users/{id}/verify") boolean verifyUser(@PathVariable String id); }
@FeignClient(name="inventory-svc", url="${inventory.url}") interface InventorySvcClient { @PostMapping("/api/inventory/reserve") boolean checkAndReserve(@RequestParam String productId, @RequestParam int qty); }
@FeignClient(name="payment-svc",   url="${payment.url}")   interface PaymentSvcClient   { @PostMapping("/api/payments") String charge(@RequestParam String userId, @RequestParam double amount); }

@Service
public class OrderOrchestrationService {
    private final UserSvcClient userClient;
    private final InventorySvcClient inventoryClient;
    private final PaymentSvcClient paymentClient;
    OrderOrchestrationService(UserSvcClient u, InventorySvcClient i, PaymentSvcClient p) {
        userClient=u; inventoryClient=i; paymentClient=p;
    }
    public String placeOrder(String userId, String productId, int qty, double amount) {
        if (!userClient.verifyUser(userId)) throw new IllegalStateException("Invalid user");
        if (!inventoryClient.checkAndReserve(productId, qty)) throw new IllegalStateException("Insufficient inventory");
        String paymentId = paymentClient.charge(userId, amount);
        return "ORD-" + paymentId.substring(0,8);
    }
}

