@FeignClient(name="holding-svc", url="${holding.url}", configuration=HoldingFeignConfig.class)
interface HoldingServiceClient {
    @GetMapping("/api/holdings") List<Holding> getHoldings(@RequestParam String userId);
    @PutMapping("/api/holdings/{id}") Holding updateHolding(@PathVariable String id, @RequestBody Holding h);
    @DeleteMapping("/api/holdings/{id}") void deleteHolding(@PathVariable String id);
}

@FeignClient(name="market-data", url="${market.url}")
interface MarketDataClient {
    @GetMapping("/api/prices") Map<String,Double> getCurrentPrices(@RequestParam List<String> symbols);
}

@Configuration class HoldingFeignConfig {
    @Bean ErrorDecoder errorDecoder(){ return (m,r)->r.status()==404?new HoldingNotFoundException("Not found"):r.status()==503?new ServiceDownException("Down"):new RuntimeException("Error: "+r.status()); }
    @Bean RequestInterceptor requestIdInterceptor(){ return t->t.header("X-Request-Id", UUID.randomUUID().toString()); }
}

@Service
public class PortfolioService {
    private final HoldingServiceClient holdingClient;
    private final MarketDataClient marketClient;
    PortfolioService(HoldingServiceClient h, MarketDataClient m){ holdingClient=h; marketClient=m; }
    public double getPortfolioValue(String userId){
        List<Holding> holdings = holdingClient.getHoldings(userId);
        List<String> symbols = holdings.stream().map(Holding::symbol).toList();
        if(symbols.isEmpty()) return 0.0;
        Map<String,Double> prices = marketClient.getCurrentPrices(symbols);
        return holdings.stream().mapToDouble(h->h.qty()*prices.getOrDefault(h.symbol(),h.avgBuyPrice())).sum();
    }
}

