import org.junit.jupiter.api.*;

@SpringBootTest(webEnvironment=SpringBootTest.WebEnvironment.NONE)
@TestPropertySource(properties={"holding.url=http://localhost:9700","market.url=http://localhost:9700"})
class PortfolioServiceTest {
    static WireMockServer wm = new WireMockServer(wireMockConfig().port(9700));
    @Autowired PortfolioService svc;
    @BeforeAll static void start(){wm.start();} @AfterAll static void stop(){wm.stop();} @BeforeEach void reset(){wm.resetAll();}

    @Test void portfolioValue_calculated() {
        wm.stubFor(get(urlPathEqualTo("/api/holdings")).willReturn(okJson("[{\"id\":\"H1\",\"userId\":\"U01\",\"symbol\":\"TCS\",\"qty\":10,\"avgBuyPrice\":3500}]")));
        wm.stubFor(get(urlPathEqualTo("/api/prices")).willReturn(okJson("{\"TCS\":3890.0}")));
        assertEquals(38900.0, svc.getPortfolioValue("U01"), 0.01);
    }
    @Test void holdingNotFound_throws(){
        wm.stubFor(get(urlPathEqualTo("/api/holdings")).willReturn(aResponse().withStatus(404)));
        assertThrows(HoldingNotFoundException.class,()->svc.getPortfolioValue("U01"));
    }
    @Test void serviceDown_throws(){
        wm.stubFor(get(urlPathEqualTo("/api/holdings")).willReturn(aResponse().withStatus(503)));
        assertThrows(ServiceDownException.class,()->svc.getPortfolioValue("U01"));
    }
    @Test void emptyPortfolio_returnsZero(){
        wm.stubFor(get(urlPathEqualTo("/api/holdings")).willReturn(okJson("[]")));
        assertEquals(0.0, svc.getPortfolioValue("U01"), 0.01);
    }
}
